import sys
input = sys.stdin.read

def main():
    data = input().split()
    H = int(data[0])
    W = int(data[1])
    N = int(data[2])
    T = data[3]
    grid = data[4:4+H]

    # Initialize possible positions
    possible_positions = set()
    for i in range(H):
        for j in range(W):
            if grid[i][j] == '.':
                possible_positions.add((i, j))

    # Simulate the moves
    for pos in list(possible_positions):
        i, j = pos
        valid = True
        for move in T:
            if move == 'L':
                ni, nj = i, j - 1
            elif move == 'R':
                ni, nj = i, j + 1
            elif move == 'U':
                ni, nj = i - 1, j
            else:  # 'D'
                ni, nj = i + 1, j
            if not (0 <= ni < H and 0 <= nj < W) or grid[ni][nj] == '#':
                valid = False
                break
            i, j = ni, nj
        if valid:
            possible_positions.add((i, j))

    print(len(possible_positions))
